 1	import React, { FC } from 'react';
 2	import { useFormContext } from 'react-hook-form';
 3	
 4	import FormGroupHelperText from '@kubevirt-utils/components/FormGroupHelperText/FormGroupHelperText';
 5	import FormPFSelect from '@kubevirt-utils/components/FormPFSelect/FormPFSelect';
 6	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 7	import { diskTypes } from '@kubevirt-utils/resources/vm/utils/disk/constants';
 8	import { getDiskDrive } from '@kubevirt-utils/resources/vm/utils/disk/selectors';
 9	import { FormGroup, SelectOption } from '@patternfly/react-core';
10	
11	import { InterfaceTypes, V1DiskFormState } from '../../utils/types';
12	
13	import { diskInterfaceOptions } from './utils/constants';
14	
15	type DiskInterfaceSelectProps = {
16	  isVMRunning: boolean;
17	};
18	
19	const DiskInterfaceSelect: FC<DiskInterfaceSelectProps> = ({ isVMRunning }) => {
20	  const { t } = useKubevirtTranslation();
21	  const { setValue, watch } = useFormContext<V1DiskFormState>();
22	  const disk = watch('disk');
23	
24	  const diskType = getDiskDrive(disk);
25	
26	  const diskInterface = disk?.[diskType]?.bus || InterfaceTypes.VIRTIO;
27	
28	  const selectedLabel = diskInterfaceOptions?.[diskInterface]?.label;
29	  return (
30	    <FormGroup fieldId="disk-interface" isRequired label={t('Interface')}>
31	      <div data-test-id="disk-interface-select">
32	        <FormPFSelect
33	          onSelect={(_, val) => setValue(`disk.${diskType}.bus`, val as string)}
34	          selected={diskInterface}
35	          selectedLabel={selectedLabel}
36	          toggleProps={{ isDisabled: isVMRunning, isFullWidth: true }}
37	        >
38	          {Object.entries(diskInterfaceOptions).map(([id, { description, label }]) => {
39	            const isDisabled = diskType === diskTypes.cdrom && id === InterfaceTypes.VIRTIO;
40	            return (
41	              <SelectOption
42	                data-test-id={`disk-interface-select-${id}`}
43	                description={description}
44	                isDisabled={isDisabled}
45	                key={id}
46	                value={id}
47	              >
48	                {label}
49	              </SelectOption>
50	            );
51	          })}
52	        </FormPFSelect>
53	        <FormGroupHelperText>
54	          {t('Hot plug is enabled only for "SCSI" interface')}
55	        </FormGroupHelperText>
56	      </div>
57	    </FormGroup>
58	  );
59	};
60	
61	export default DiskInterfaceSelect;

